flowchart TD
  A[API request arrives] --> B{Explicit Deny anywhere}
  B -- Yes --> X[DENY]
  B -- No --> C{Allowed by SCP ceiling}
  C -- No --> X
  C -- Yes --> D{Within permission boundary}
  D -- No --> X
  D -- Yes --> E{Within session policy}
  E -- No --> X
  E -- Yes --> F{Explicit Allow in identity or resource policy}
  F -- No --> X
  F -- Yes --> G[ALLOW]

