{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowVendorAuditRoleWithExternalId",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::999988887777:role/audit-runner"
      },
      "Action": "sts:AssumeRole",
      "Condition": {
        "StringEquals": {
          "sts:ExternalId": "acme-9f12-tenant"
        }
      }
    },
    {
      "Sid": "DenyAssumeWithoutExternalId",
      "Effect": "Deny",
      "Principal": { "AWS": "*" },
      "Action": "sts:AssumeRole",
      "Condition": {
        "Null": { "sts:ExternalId": "true" }
      }
    }
  ]
}

